const OPENAI_API_KEY = "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";

// 🔥 BLOG GENERATION
export async function generateBlog(title) {
  try {
    const res = await fetch("https://api.openai.com/v1/chat/completions", {
      method: "POST",
      headers: {
        "Content-Type": "application/json",
        Authorization: `Bearer ${OPENAI_API_KEY}`,
      },
      body: JSON.stringify({
        model: "gpt-4o-mini",
        messages: [
          {
            role: "system",
            content:
              "Write a blog article (300-500 words) in simple language.",
          },
          {
            role: "user",
            content: title,
          },
        ],
      }),
    });

    const data = await res.json();
    return data.choices?.[0]?.message?.content || "No content generated.";
  } catch (err) {
    console.error(err);
    return `This is a fallback article about ${title}.`;
  }
}

// 🔥 TAG GENERATION
export async function generateTags(title, content) {
  try {
    const text = `${title} ${content}`.toLowerCase();

    const words = text.split(/\W+/).filter((w) => w.length > 4);

    return [...new Set(words)].slice(0, 5);
  } catch {
    return ["blog", "article"];
  }
}

// 🔥 WRITING ANALYSIS
export async function analyzeWriting(title, content) {
  return {
    score: 8,
    tone: "Professional",
    readability: "Medium",
    strengths: ["Clear topic", "Good structure"],
    improvements: ["Add examples", "Improve conclusion"],
    rewrittenIntro: `This article explores ${title} in a clear way.`,
  };
}

// 🔥 SUMMARY
export async function generateSummary(title, content) {
  return content.slice(0, 120) + "...";
}

// 🔥 SENTIMENT
export async function analyzeCommentSentiment(text) {
  return {
    sentiment: "Positive",
    score: 0.85,
  };
}

// 🔥 RECOMMENDATIONS
export async function getRecommendations(history, posts) {
  return posts?.slice(0, 3) || [];
}
